# Angular Debugging Guide

## Change Detection Not Triggering

### Problem
UI not updating after data changes.

### Solutions
```typescript
// With OnPush, must use immutable updates
@Component({
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class ListComponent {
  items = signal<Item[]>([]);

  // BAD: Mutating array
  addItem(item: Item) {
    this.items().push(item);  // Won't trigger!
  }

  // GOOD: Create new array
  addItem(item: Item) {
    this.items.update(items => [...items, item]);
  }
}

// Force change detection if needed
constructor(private cdr: ChangeDetectorRef) {}

ngAfterViewInit() {
  // After async operation
  this.cdr.detectChanges();
}
```

## Dependency Injection Errors

```typescript
// ERROR: NullInjectorError: No provider for ServiceX

// Solution 1: providedIn root
@Injectable({ providedIn: 'root' })
export class AuthService {}

// Solution 2: Provide in component
@Component({
  providers: [MyService]  // New instance per component
})

// Solution 3: Provide in route
{
  path: 'admin',
  providers: [AdminService],
  loadComponent: () => import('./admin.component')
}
```

## Observable Memory Leaks

```typescript
// BAD: Not unsubscribing
export class MyComponent {
  ngOnInit() {
    this.http.get('/api/data').subscribe(data => {
      this.data = data;  // Leaks if component destroyed!
    });
  }
}

// GOOD: Using takeUntilDestroyed (Angular 16+)
export class MyComponent {
  private destroyRef = inject(DestroyRef);

  ngOnInit() {
    this.http.get('/api/data')
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe(data => this.data = data);
  }
}

// GOOD: Using async pipe (auto-unsubscribes)
@Component({
  template: `<div *ngIf="data$ | async as data">{{ data.name }}</div>`
})
export class MyComponent {
  data$ = this.http.get('/api/data');
}
```
